code.python:
def my_sqrt(x):
    if x < 2:
        return x
    lo, hi = 1, x // 2
    while lo <= hi:
        mid = (lo + hi) // 2
        sq = mid * mid
        if sq == x:
            return mid
        if sq < x:
            lo = mid + 1
        else:
            hi = mid - 1
    return hi

code.javascript:
function mySqrt(x) {
  if (x < 2) {
    return x;
  }
  let lo = 1;
  let hi = Math.floor(x / 2);
  while (lo <= hi) {
    const mid = Math.floor((lo + hi) / 2);
    const sq = mid * mid;
    if (sq === x) {
      return mid;
    }
    if (sq < x) {
      lo = mid + 1;
    } else {
      hi = mid - 1;
    }
  }
  return hi;
}

code.typescript:
function mySqrt(x: number): number {
  if (x < 2) {
    return x;
  }
  let lo = 1;
  let hi = Math.floor(x / 2);
  while (lo <= hi) {
    const mid = Math.floor((lo + hi) / 2);
    const sq = mid * mid;
    if (sq === x) {
      return mid;
    }
    if (sq < x) {
      lo = mid + 1;
    } else {
      hi = mid - 1;
    }
  }
  return hi;
}
